const baseUrl = '{{SUPABASE_URL}}';
const serviceKey = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': serviceKey,
  'Authorization': 'Bearer ' + serviceKey,
  'Content-Type': 'application/json'
};

const now = new Date();
const todayStr = now.toISOString().split('T')[0];
const yesterdayStr = new Date(now - 86400000).toISOString().split('T')[0];

// 1. New reviews since yesterday
let newReviews = [];
try {
  newReviews = await helpers.httpRequest({
    method: 'GET',
    url: baseUrl + '/rest/v1/reviews?fetched_at=gte.' + yesterdayStr + '&select=*,member_businesses(name)&order=rating.asc',
    headers: pgHeaders
  });
} catch(e) { newReviews = []; }

// 2. Scheduled posts for today
let todayPosts = [];
try {
  todayPosts = await helpers.httpRequest({
    method: 'GET',
    url: baseUrl + '/rest/v1/scheduled_posts?scheduled_at=gte.' + todayStr + 'T00:00:00&scheduled_at=lte.' + todayStr + 'T23:59:59&select=*&order=scheduled_at.asc',
    headers: pgHeaders
  });
} catch(e) { todayPosts = []; }

// 3. Pending tasks
let pendingTasks = [];
try {
  pendingTasks = await helpers.httpRequest({
    method: 'GET',
    url: baseUrl + '/rest/v1/tasks?status=in.(pending,in_progress)&parent_id=is.null&order=priority.desc,due_date.asc.nullslast&select=id,title,priority,due_date,status',
    headers: pgHeaders
  });
} catch(e) { pendingTasks = []; }

// 4. Weather (call Open-Meteo for the region)
let weather = null;
try {
  const w = await helpers.httpRequest({
    method: 'GET',
    url: 'https://api.open-meteo.com/v1/forecast?latitude=47.4&longitude=11.1&current=temperature_2m,weather_code,snow_depth&daily=temperature_2m_max,temperature_2m_min,precipitation_probability_max,snowfall_sum&timezone=Europe/Berlin&forecast_days=1'
  });
  const weatherCodes = {0:'Klar',1:'Überwiegend klar',2:'Teilweise bewölkt',3:'Bewölkt',45:'Nebel',61:'Leichter Regen',63:'Regen',71:'Leichter Schneefall',73:'Schneefall',75:'Starker Schneefall',95:'Gewitter'};
  weather = {
    temp: w.current.temperature_2m,
    condition: weatherCodes[w.current.weather_code] || 'Code ' + w.current.weather_code,
    snow_depth: w.current.snow_depth,
    max: w.daily.temperature_2m_max[0],
    min: w.daily.temperature_2m_min[0],
    precip_prob: w.daily.precipitation_probability_max[0],
    snowfall: w.daily.snowfall_sum[0]
  };
} catch(e) { weather = null; }

// Build briefing text
let briefing = '# ☀️ Morgen-Briefing — ' + new Date().toLocaleDateString('de-DE', {weekday:'long', day:'numeric', month:'long', year:'numeric', timeZone:'Europe/Berlin'}) + '\n\n';

// Weather
if (weather) {
  briefing += '## 🌡️ Wetter\n';
  briefing += weather.temp + '°C, ' + weather.condition;
  if (weather.snow_depth > 0) briefing += ', Schneehöhe: ' + weather.snow_depth + ' cm';
  briefing += '\nMin/Max: ' + weather.min + '/' + weather.max + '°C';
  if (weather.precip_prob > 0) briefing += ', Niederschlag: ' + weather.precip_prob + '%';
  if (weather.snowfall > 0) briefing += ', Neuschnee: ' + weather.snowfall + ' cm';
  briefing += '\n\n';
}

// Reviews
if (newReviews.length > 0) {
  briefing += '## ⭐ Neue Bewertungen (' + newReviews.length + ')\n';
  const avgRating = (newReviews.reduce((s,r) => s + r.rating, 0) / newReviews.length).toFixed(1);
  const lowReviews = newReviews.filter(r => r.rating <= 3);
  briefing += 'Durchschnitt: ' + avgRating + '★';
  if (lowReviews.length > 0) briefing += ' ⚠️ ' + lowReviews.length + ' kritische Bewertung(en)';
  briefing += '\n';
  newReviews.slice(0, 5).forEach(r => {
    const biz = r.member_businesses?.name || 'Unbekannt';
    briefing += '- ' + '★'.repeat(r.rating) + ' ' + biz + ': ' + (r.text || '').substring(0, 80) + '\n';
  });
  briefing += '\n';
} else {
  briefing += '## ⭐ Bewertungen\nKeine neuen Bewertungen seit gestern.\n\n';
}

// Posts
if (todayPosts.length > 0) {
  briefing += '## 📱 Geplante Posts heute (' + todayPosts.length + ')\n';
  todayPosts.forEach(p => {
    const time = new Date(p.scheduled_at).toLocaleTimeString('de-DE', {hour:'2-digit', minute:'2-digit', timeZone:'Europe/Berlin'});
    briefing += '- ' + time + ' ' + p.platform + ': ' + (p.caption || '').substring(0, 60) + ' [' + p.status + ']\n';
  });
  briefing += '\n';
} else {
  briefing += '## 📱 Posts\nKeine Posts für heute geplant.\n\n';
}

// Tasks
if (pendingTasks.length > 0) {
  const urgent = pendingTasks.filter(t => t.priority === 'urgent' || t.priority === 'high');
  briefing += '## ✅ Aufgaben (' + pendingTasks.length + ' offen';
  if (urgent.length > 0) briefing += ', ' + urgent.length + ' dringend';
  briefing += ')\n';
  pendingTasks.slice(0, 5).forEach(t => {
    const due = t.due_date ? ' (fällig: ' + new Date(t.due_date).toLocaleDateString('de-DE', {timeZone:'Europe/Berlin'}) + ')' : '';
    briefing += '- [' + t.priority + '] ' + t.title + due + '\n';
  });
  briefing += '\n';
}

// Save briefing to DB
try {
  await helpers.httpRequest({
    method: 'POST',
    url: baseUrl + '/rest/v1/memory_daily',
    headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      date: todayStr,
      content: briefing,
      role: 'briefing',
      user_id: 'system'
    })
  });
} catch(e) {}

return [{ json: { briefing, date: todayStr } }];
